noncompliant:
if (x != a)  // Noncompliant - redundant check before assignment
{
    x = a;
}

if (name != newName) // Noncompliant - unnecessary comparison
{
    name = newName;
}

compliant:
// Property exception - check may be needed for side effects
if (MyProperty != a)
{
    MyProperty = a; // Compliant - setter might have side effects
}
